class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;

    TreeNode(int x) {
        val = x;
    }
}

public class Solution {
    public String smallestFromLeaf(TreeNode root) {
        if (root == null) return "|";
        String s = Character.toString((char) (root.val + 'a'));
        if (root.left == null && root.right == null) return s;
        String left = smallestFromLeaf(root.left);
        String right = smallestFromLeaf(root.right);
        return (left.compareTo(right) <= 0 ? left : right) + s;
    }
}
```

